    struct TempDirGuard {
        path: PathBuf,
    }

    impl TempDirGuard {
        fn new(prefix: &str) -> Self {
            let nanos = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .map(|d| d.as_nanos())
                .unwrap_or(0);
            let path = std::env::temp_dir().join(format!(
                "whitebox_workflows_{}_{}_{}",
                prefix,
                std::process::id(),
                nanos
            ));
            std::fs::create_dir_all(&path).unwrap();
            Self { path }
        }

        fn path(&self) -> &Path {
            &self.path
        }
    }

    impl Drop for TempDirGuard {
        fn drop(&mut self) {
            let _ = std::fs::remove_dir_all(&self.path);
        }
    }

    fn make_test_raster(path: &Path) -> Raster {
        let cfg = wbraster::RasterConfig {
            cols: 6,
            rows: 5,
            x_min: -80.0,
            y_min: 40.0,
            cell_size: 0.1,
            nodata: -9999.0,
            crs: CrsInfo::from_epsg(4326),
            ..Default::default()
        };
        let mut raster = WbRaster::new(cfg);
        for row in 0..raster.rows {
            for col in 0..raster.cols {
                raster
                    .set(0, row as isize, col as isize, (row * raster.cols + col) as f64)
                    .unwrap();
            }
        }
        raster.write_auto(path).unwrap();
        Raster {
            file_path: path.to_path_buf(),
            active_band: 0,
        }
    }

    fn make_test_vector(path: &Path) -> Vector {
        let mut layer = WbLayer::new("cities")
            .with_geom_type(GeometryType::Point)
            .with_crs_epsg(4326);
        layer.add_feature(Some(Geometry::point(-75.0, 45.0)), &[]).unwrap();
        layer.add_feature(Some(Geometry::point(-74.0, 46.0)), &[]).unwrap();
        layer.add_feature(Some(Geometry::point(-73.0, 47.0)), &[]).unwrap();
        wbvector::write(&layer, path, VectorFormat::GeoPackage).unwrap();
        Vector {
            file_path: path.to_path_buf(),
        }
    }

    fn make_test_vector_with_attributes(path: &Path) -> Vector {
        let mut layer = WbLayer::new("cities")
            .with_geom_type(GeometryType::Point)
            .with_crs_epsg(4326);
        layer.add_field(FieldDef::new("name", FieldType::Text));
        layer.add_field(FieldDef::new("count", FieldType::Integer));
        layer
            .add_feature(
                Some(Geometry::point(-75.0, 45.0)),
                &[("name", "alpha".into()), ("count", 1i64.into())],
            )
            .unwrap();
        layer
            .add_feature(
                Some(Geometry::point(-74.0, 46.0)),
                &[("name", "beta".into()), ("count", 2i64.into())],
            )
            .unwrap();
        wbvector::write(&layer, path, VectorFormat::GeoPackage).unwrap();
        Vector {
            file_path: path.to_path_buf(),
        }
    }

